let raw = $json.message ?? $json.payload ?? $json.data ?? $json;

for (let i = 0; i < 3; i++) {
  if (typeof raw === 'string') {
    try {
      raw = JSON.parse(raw);
    } catch {
      break;
    }
    continue;
  }

  if (raw && typeof raw === 'object') {
    if (typeof raw.message === 'string' || (raw.message && typeof raw.message === 'object')) {
      raw = raw.message;
      continue;
    }
    break;
  }

  break;
}

let data = raw;
if (!data || typeof data !== 'object') {
  data = {};
}

const normalized = {
  ...data,
  id: data.id ?? data.after?.id,
  type: data.type ?? data.after?.type ?? data.label ?? data.after?.label,
  name: data.name ?? data.after?.sub_label ?? data.sub_label ?? data.after?.label ?? data.label ?? '',
  score: data.score ?? data.after?.score ?? data.top_score ?? data.after?.top_score,
  camera: data.camera ?? data.after?.camera,
  timestamp: data.timestamp ?? data.after?.frame_time ?? data.after?.start_time,
};

const typeNorm = String(normalized.type ?? '').trim().toLowerCase();
const nameNorm = String(normalized.name ?? '').trim().toLowerCase();

const isPerson = ['person', 'persona', 'face', 'rostro'].includes(typeNorm);
const isMotorcycle = ['motorcycle', 'motorbike', 'moto', 'motocicleta'].includes(typeNorm);
const isVehicle = isMotorcycle || ['car', 'vehicle', 'vehiculo', 'vehiculo', 'truck', 'bus', 'van'].includes(typeNorm);

const suspiciousKeywords = ['sospechoso', 'suspicious', 'sin placa', 'sin_placa', 'sin-placa', 'robado', 'robo'];
const hasSuspiciousKeyword = suspiciousKeywords.some((keyword) => nameNorm.includes(keyword));
const hasUnknownId = !nameNorm || ['unknown', 'desconocido', 'desconocida', 'n/a', 'na'].includes(nameNorm);
const isSuspiciousVehicle = isVehicle && (hasSuspiciousKeyword || hasUnknownId);

const ts = normalized.timestamp ? new Date(normalized.timestamp * 1000) : new Date();
const horaLegible = ts.toLocaleString('es-HN', {
  timeZone: 'America/Tegucigalpa',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: true,
});

return [{
  json: {
    ...normalized,
    topic: $json.topic,
    hora_legible: horaLegible,
    is_person: isPerson,
    is_motorcycle: isMotorcycle,
    is_vehicle: isVehicle,
    is_suspicious_vehicle: isSuspiciousVehicle,
  }
}];
